1	import { useCallback, useEffect, useMemo, useState } from 'react';
2	import {
3	  ActivityIndicator,
4	  KeyboardAvoidingView,
5	  Platform as RNPlatform,
6	  SafeAreaView,
7	  ScrollView,
8	  StyleSheet,
9	  Text,
10	  TextInput,
11	  View,
12	} from 'react-native';
13	import { BottomSheet } from '@/components/primitives/BottomSheet';
14	import { ButtonPrimary, ButtonSecondary } from '@/components/primitives/Button';
15	import { useToast } from '@/components/primitives/Toast';
16	import { colors, radii, shadows, spacing } from '@/design/tokens';
17	import { textStyles } from '@/design/typography';
18	import { useAuth } from '@/lib/auth';
19	import { supabase } from '@/lib/supabase';
20	import { formatRelativeTime } from '@/lib/time';
21	import type { Database } from '@/types/supabase';
22	
23	// US-035 — creator profile. Shows TikTok + Instagram handles with their
24	// denormalized follower counts / avg views, a "Stale" chip when the latest
25	// metric_snapshot was flipped to status='stale' by the hourly cron, and an
26	// Add / Unlink flow wired to the manage-social-link edge function.
27	//
28	// Spec gap: the story AC says "Stale chip appears when metrics_stale_at is
29	// non-null", but there is no metrics_stale_at column on creator_profiles
30	// (see us_004 + the us_011 cron which flips metric_snapshots.status='stale'
31	// instead). The chip is therefore derived from
32	// metric_snapshots WHERE is_latest = true AND status = 'stale', which is
33	// the signal the cron actually produces per docs/tech-architecture.md §16.
34	//
35	// Apify scrapes on add are deferred to US-036 (pull-to-refresh) to keep
36	// this story focused on the CRUD flow — matches the story AC wording
37	// ("small edge function").
38	
39	type SocialPlatform = Database['public']['Enums']['platform'];
40	type SocialLink = Database['public']['Tables']['social_links']['Row'];
41	type CreatorProfileRow = Database['public']['Tables']['creator_profiles']['Row'];
42	
43	const HANDLE_RE = /^[a-zA-Z0-9_.]{1,30}$/;
44	const PLATFORMS: readonly SocialPlatform[] = ['tiktok', 'instagram'];
45	
46	export default function CreatorProfile() {
47	  const { user, signOut } = useAuth();
48	  const { show: showToast } = useToast();
49	
50	  const [profile, setProfile] = useState<CreatorProfileRow | null>(null);
51	  const [links, setLinks] = useState<SocialLink[]>([]);
52	  const [snapshotByLink, setSnapshotByLink] = useState<
53	    Map<string, { status: Database['public']['Enums']['metric_status']; fetched_at: string }>
54	  >(new Map());
55	  const [loading, setLoading] = useState(true);
56	  const [pendingAction, setPendingAction] = useState<string | null>(null);
57	  const [sheetPlatform, setSheetPlatform] = useState<SocialPlatform | null>(null);
58	
59	  const load = useCallback(async () => {
60	    if (!user) return;
61	    setLoading(true);
62	    try {
63	      const [profileRes, linksRes] = await Promise.all([
64	        supabase
65	          .from('creator_profiles')
66	          .select('*')
67	          .eq('user_id', user.id)
68	          .maybeSingle(),
69	        supabase
70	          .from('social_links')
71	          .select('*')
72	          .eq('user_id', user.id)
73	          .neq('status', 'unlinked'),
74	      ]);
75	      if (profileRes.error) throw profileRes.error;
76	      if (linksRes.error) throw linksRes.error;
77	      const linkRows = linksRes.data ?? [];
78	      const linkIds = linkRows.map((l) => l.id);
79	      const snapshotMap = new Map<
80	        string,
81	        { status: Database['public']['Enums']['metric_status']; fetched_at: string }
82	      >();
83	      if (linkIds.length > 0) {
84	        const snapsRes = await supabase
85	          .from('metric_snapshots')
86	          .select('social_link_id, status, fetched_at')
87	          .eq('is_latest', true)
88	          .in('social_link_id', linkIds);
89	        if (snapsRes.error) throw snapsRes.error;
90	        for (const row of snapsRes.data ?? []) {
91	          snapshotMap.set(row.social_link_id, {
92	            status: row.status,
93	            fetched_at: row.fetched_at,
94	          });
95	        }
96	      }
97	      setProfile(profileRes.data ?? null);
98	      setLinks(linkRows);
99	      setSnapshotByLink(snapshotMap);
100	    } catch (err) {
101	      console.error('Profile load failed', err);
102	      showToast({ message: 'Could not load profile.', variant: 'error' });
103	    } finally {
104	      setLoading(false);
105	    }
106	  }, [user, showToast]);
107	
108	  useEffect(() => {
109	    void load();
110	  }, [load]);
111	
112	  const sections = useMemo(() => {
113	    return PLATFORMS.map((platform) => {
114	      const link = links.find((l) => l.platform === platform) ?? null;
115	      const snap = link ? snapshotByLink.get(link.id) ?? null : null;
116	      const isStale = snap?.status === 'stale';
117	      const lastRefreshedAt = snap?.fetched_at ?? null;
118	      return { platform, link, isStale, lastRefreshedAt };
119	    });
120	  }, [links, snapshotByLink]);
121	
122	  const onAdd = useCallback(
123	    async (platform: SocialPlatform, rawHandle: string) => {
124	      const handle = rawHandle.trim().replace(/^@+/, '').trim();
125	      if (!HANDLE_RE.test(handle)) {
126	        showToast({
127	          message: 'Handle must be letters, numbers, underscores, or dots.',
128	          variant: 'error',
129	        });
130	        return;
131	      }
132	      setPendingAction(`add:${platform}`);
133	      try {
134	        const { data, error } = await supabase.functions.invoke<{ social_link_id: string }>(
135	          'manage-social-link',
136	          { body: { action: 'add', platform, handle } },
137	        );
138	        if (error) {
139	          const ctx = (error as { context?: unknown }).context;
140	          if (
141	            ctx &&
142	            typeof ctx === 'object' &&
143	            'status' in ctx &&
144	            typeof (ctx as { json?: unknown }).json === 'function'
145	          ) {
146	            const res = ctx as Response;
147	            let body: { error?: string } = {};
148	            try {
149	              body = (await res.json()) as { error?: string };
150	            } catch {
151	              // non-JSON body — fall through to generic toast
152	            }
153	            if (res.status === 409 && body.error === 'ALREADY_LINKED') {
154	              showToast({
155	                message: `You already have a ${platformLabel(platform)} handle linked.`,
156	                variant: 'error',
157	              });
158	              return;
159	            }
160	            if (res.status === 409 && body.error === 'HANDLE_TAKEN') {
161	              showToast({
162	                message: 'That handle is already linked to another account.',
163	                variant: 'error',
164	              });
165	              return;
166	            }
167	          }
168	          showToast({ message: 'Could not add handle.', variant: 'error' });
169	          return;
170	        }
171	        if (!data?.social_link_id) {
172	          showToast({ message: 'Could not add handle.', variant: 'error' });
173	          return;
174	        }
175	        setSheetPlatform(null);
176	        showToast({
177	          message: `${platformLabel(platform)} handle added.`,
178	          variant: 'success',
179	        });
180	        await load();
181	      } finally {
182	        setPendingAction(null);
183	      }
184	    },
185	    [showToast, load],
186	  );
187	
188	  const onUnlink = useCallback(
189	    async (link: SocialLink) => {
190	      setPendingAction(`unlink:${link.id}`);
191	      try {
192	        const { error } = await supabase.functions.invoke('manage-social-link', {
193	          body: { action: 'unlink', social_link_id: link.id },
194	        });
195	        if (error) {
196	          showToast({ message: 'Could not unlink handle.', variant: 'error' });
197	          return;
198	        }
199	        showToast({
200	          message: `${platformLabel(link.platform)} handle unlinked.`,
201	          variant: 'success',
202	        });
203	        await load();
204	      } finally {
205	        setPendingAction(null);
206	      }
207	    },
208	    [showToast, load],
209	  );
210	
211	  return (
212	    <SafeAreaView style={styles.container}>
213	      <ScrollView contentContainerStyle={styles.scrollContent}>
214	        <View style={styles.header}>
215	          <Text style={[textStyles.display, { color: colors.ink }]}>Profile</Text>
216	          {user ? (
217	            <Text style={[textStyles.mono, styles.usernameRow]}>@{user.username}</Text>
218	          ) : null}
219	        </View>
220	
221	        {loading && profile === null ? (
222	          <View style={styles.loadingBlock}>
223	            <ActivityIndicator color={colors.ink} />
224	          </View>
225	        ) : (
226	          <View style={styles.sections}>
227	            {sections.map(({ platform, link, isStale, lastRefreshedAt }) => (
228	              <PlatformCard
229	                key={platform}
230	                platform={platform}
231	                link={link}
232	                profile={profile}
233	                isStale={isStale}
234	                lastRefreshedAt={lastRefreshedAt}
235	                pendingAction={pendingAction}
236	                onOpenAdd={() => setSheetPlatform(platform)}
237	                onUnlink={onUnlink}
238	              />
239	            ))}
240	          </View>
241	        )}
242	
243	        <View style={styles.signOutWrap}>
244	          <ButtonSecondary
245	            label="Sign out"
246	            onPress={signOut}
247	            accessibilityLabel="Sign out"
248	            testID="creator-signout"
249	          />
250	        </View>
251	      </ScrollView>
252	
253	      <AddHandleSheet
254	        platform={sheetPlatform}
255	        onDismiss={() => setSheetPlatform(null)}
256	        onSubmit={onAdd}
257	        submitting={sheetPlatform !== null && pendingAction === `add:${sheetPlatform}`}
258	      />
259	    </SafeAreaView>
260	  );
261	}
262	
263	type PlatformCardProps = {
264	  platform: SocialPlatform;
265	  link: SocialLink | null;
266	  profile: CreatorProfileRow | null;
267	  isStale: boolean;
268	  lastRefreshedAt: string | null;
269	  pendingAction: string | null;
270	  onOpenAdd: () => void;
271	  onUnlink: (link: SocialLink) => void;
272	};
273	
274	function PlatformCard({
275	  platform,
276	  link,
277	  profile,
278	  isStale,
279	  lastRefreshedAt,
280	  pendingAction,
281	  onOpenAdd,
282	  onUnlink,
283	}: PlatformCardProps) {
284	  const { follower, avgViews } = extractMetrics(platform, profile);
285	  const lastRefreshedLabel = lastRefreshedAt
286	    ? formatRelativeTime(new Date(lastRefreshedAt))
287	    : 'Never';
288	  const unlinkLoading = link ? pendingAction === `unlink:${link.id}` : false;
289	
290	  return (
291	    <View style={styles.card}>
292	      <View style={styles.cardHeader}>
293	        <Text style={[textStyles.h2, { color: colors.ink }]}>{platformLabel(platform)}</Text>
294	        {isStale && link ? <StaleChip /> : null}
295	      </View>
296	
297	      {link ? (
298	        <>
299	          <Text style={[textStyles.mono, styles.handleRow]}>@{link.handle}</Text>
300	          <View style={styles.metricsRow}>
301	            <Metric label="Followers" value={formatCount(follower)} />
302	            <Metric label="Avg views" value={formatCount(avgViews)} />
303	          </View>
304	          <Text style={[textStyles.caption, styles.lastRefreshed]}>
305	            Last refreshed {lastRefreshedLabel}
306	          </Text>
307	          <View style={styles.cardAction}>
308	            <ButtonSecondary
309	              label="Unlink handle"
310	              onPress={() => onUnlink(link)}
311	              loading={unlinkLoading}
312	              disabled={unlinkLoading}
313	              accessibilityLabel={`Unlink ${platformLabel(platform)} handle`}
314	              testID={`unlink-${platform}`}
315	            />
316	          </View>
317	        </>
318	      ) : (
319	        <>
320	          <Text style={[textStyles.body, styles.emptyRow]}>
321	            No {platformLabel(platform)} handle linked.
322	          </Text>
323	          <View style={styles.cardAction}>
324	            <ButtonPrimary
325	              label={`Add ${platformLabel(platform)} handle`}
326	              onPress={onOpenAdd}
327	              accessibilityLabel={`Add ${platformLabel(platform)} handle`}
328	              testID={`add-${platform}`}
329	            />
330	          </View>
331	        </>
332	      )}
333	    </View>
334	  );
335	}
336	
337	function Metric({ label, value }: { label: string; value: string }) {
338	  return (
339	    <View style={styles.metric}>
340	      <Text style={[textStyles.caption, { color: colors.ink70 }]}>{label}</Text>
341	      <Text style={[textStyles.h1, { color: colors.ink }]}>{value}</Text>
342	    </View>
343	  );
344	}
345	
346	function StaleChip() {
347	  return (
348	    <View
349	      style={[styles.stalePill, shadows.hard]}
350	      accessible
351	      accessibilityLabel="Metrics are stale"
352	      testID="stale-chip"
353	    >
354	      <Text style={[textStyles.micro, { color: colors.warning }]} allowFontScaling={false}>
355	        Stale
356	      </Text>
357	    </View>
358	  );
359	}
360	
361	function AddHandleSheet({
362	  platform,
363	  onDismiss,
364	  onSubmit,
365	  submitting,
366	}: {
367	  platform: SocialPlatform | null;
368	  onDismiss: () => void;
369	  onSubmit: (platform: SocialPlatform, handle: string) => void;
370	  submitting: boolean;
371	}) {
372	  const [value, setValue] = useState('');
373	  useEffect(() => {
374	    if (platform !== null) setValue('');
375	  }, [platform]);
376	  const normalized = value.trim().replace(/^@+/, '').trim();
377	
378	  return (
379	    <BottomSheet
380	      visible={platform !== null}
381	      onDismiss={onDismiss}
382	      snapPoints={[0.5]}
383	      accessibilityLabel="Add handle"
384	    >
385	      {platform ? (
386	        <KeyboardAvoidingView
387	          behavior={RNPlatform.OS === 'ios' ? 'padding' : undefined}
388	          style={styles.sheetBody}
389	        >
390	          <Text style={[textStyles.h1, { color: colors.ink }]}>
391	            Add {platformLabel(platform)} handle
392	          </Text>
393	          <Text style={[textStyles.body, styles.sheetHint]}>
394	            We&apos;ll pull your latest stats on next refresh.
395	          </Text>
396	          <View style={[styles.inputWrap, shadows.hard]}>
397	            <TextInput
398	              value={value}
399	              onChangeText={setValue}
400	              autoCapitalize="none"
401	              autoCorrect={false}
402	              autoComplete="off"
403	              placeholder={platform === 'tiktok' ? '@yourtiktok' : '@yourinsta'}
404	              placeholderTextColor={colors.ink40}
405	              style={[textStyles.mono, styles.input]}
406	              editable={!submitting}
407	              accessibilityLabel={`${platformLabel(platform)} handle`}
408	              testID={`sheet-handle-input-${platform}`}
409	            />
410	          </View>
411	          <ButtonPrimary
412	            label="Add handle"
413	            onPress={() => onSubmit(platform, value)}
414	            loading={submitting}
415	            disabled={submitting || normalized.length === 0}
416	            accessibilityLabel={`Add ${platformLabel(platform)} handle`}
417	            testID={`sheet-add-${platform}`}
418	          />
419	        </KeyboardAvoidingView>
420	      ) : null}
421	    </BottomSheet>
422	  );
423	}
424	
425	function extractMetrics(
426	  platform: SocialPlatform,
427	  profile: CreatorProfileRow | null,
428	): { follower: number | null; avgViews: number | null } {
429	  if (!profile) return { follower: null, avgViews: null };
430	  if (platform === 'tiktok') {
431	    return {
432	      follower: profile.tiktok_follower_count,
433	      avgViews: profile.tiktok_avg_views_last_10,
434	    };
435	  }
436	  return {
437	    follower: profile.instagram_follower_count,
438	    avgViews: profile.instagram_avg_views_last_10,
439	  };
440	}
441	
442	function platformLabel(p: SocialPlatform): string {
443	  return p === 'tiktok' ? 'TikTok' : 'Instagram';
444	}
445	
446	function formatCount(n: number | null): string {
447	  if (n === null) return '—';
448	  if (n < 1000) return String(n);
449	  if (n < 1_000_000) return `${(n / 1000).toFixed(n < 10_000 ? 1 : 0)}k`;
450	  return `${(n / 1_000_000).toFixed(n < 10_000_000 ? 1 : 0)}m`;
451	}
452	
453	const styles = StyleSheet.create({
454	  container: {
455	    flex: 1,
