// Edge function: manage-social-link (US-035)
//
// Contract:
//   POST add:    { action: 'add', platform: 'tiktok'|'instagram', handle: string }
//     → 200 { social_link_id: string }
//   POST unlink: { action: 'unlink', social_link_id: string }
//     → 200 { ok: true }
//     → 400 { error: 'INVALID_JSON' | 'INVALID_REQUEST' }
//     → 401 { error: 'UNAUTHORIZED' }
//     → 403 { error: 'FORBIDDEN' }
//     → 404 { error: 'LINK_NOT_FOUND' }
//     → 409 { error: 'ALREADY_LINKED' | 'HANDLE_TAKEN' }
//     → 500 { error: 'SERVER_MISCONFIGURED' | 'DB_ERROR' }
//
// Auth: Marketify JWT (HS256, MARKETIFY_JWT_SECRET). Verifies via
//       _shared/jwt.ts and asserts role='creator'. Deployed with
//       verify_jwt=false at the gateway; the handler enforces auth.
//
// Atomicity: single INSERT (add) or single UPDATE (unlink) inside the
// public.manage_social_link RPC's implicit transaction.
//
// Scope: this function does NOT kick Apify scrapes on add. Pulling metrics
// for a freshly-added handle is the job of US-036 (pull-to-refresh on
// Profile) — a pattern identical to metrics-refresh. Keeping scope tight
// here matches the story AC ("Add Handle / Unlink Handle actions wired to
// a small edge function").

import { createClient } from "npm:@supabase/supabase-js@2";
import { verifyJwt } from "../_shared/jwt.ts";
import { corsHeaders } from "../_shared/cors.ts";

const UUID_RE =
  /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
const HANDLE_RE = /^[a-zA-Z0-9_.]{1,30}$/;

type Platform = "tiktok" | "instagram";

interface AddRequest {
  action?: "add";
  platform?: unknown;
  handle?: unknown;
}
interface UnlinkRequest {
  action?: "unlink";
  social_link_id?: unknown;
}
type AnyRequest = AddRequest | UnlinkRequest | { action?: unknown };

function jsonResponse(status: number, body: unknown): Response {
  return new Response(JSON.stringify(body), {
    status,
    headers: { ...corsHeaders, "Content-Type": "application/json" },
  });
}

function bearerToken(req: Request): string | null {
  const raw = req.headers.get("Authorization") ??
    req.headers.get("authorization");
  if (!raw) return null;
  const m = raw.match(/^Bearer\s+(.+)$/i);
  return m ? m[1].trim() : null;
}

function normalizeHandle(value: unknown): string | null {
  if (typeof value !== "string") return null;
  const stripped = value.trim().replace(/^@+/, "").trim();
  if (stripped.length === 0 || !HANDLE_RE.test(stripped)) return null;
  return stripped;
}

function parsePlatform(value: unknown): Platform | null {
  return value === "tiktok" || value === "instagram" ? value : null;
}

Deno.serve(async (req) => {
  if (req.method === "OPTIONS") {
    return new Response(null, { status: 204, headers: corsHeaders });
  }
  if (req.method !== "POST") {
    return jsonResponse(405, { error: "METHOD_NOT_ALLOWED" });
  }

  const token = bearerToken(req);
  if (!token) return jsonResponse(401, { error: "UNAUTHORIZED" });

  let claims;
  try {
    claims = await verifyJwt(token);
  } catch {
    return jsonResponse(401, { error: "UNAUTHORIZED" });
  }
  if (claims.role !== "creator") {
    return jsonResponse(403, { error: "FORBIDDEN" });
  }

  let body: AnyRequest;
  try {
    body = await req.json();
  } catch {
    return jsonResponse(400, { error: "INVALID_JSON" });
  }

  const supabaseUrl = Deno.env.get("SUPABASE_URL");
  const serviceRoleKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY");
  if (!supabaseUrl || !serviceRoleKey) {
    return jsonResponse(500, { error: "SERVER_MISCONFIGURED" });
  }
  const supabase = createClient(supabaseUrl, serviceRoleKey, {
    auth: { persistSession: false, autoRefreshToken: false },
  });

  if (body.action === "add") {
    const platform = parsePlatform((body as AddRequest).platform);
    const handle = normalizeHandle((body as AddRequest).handle);
    if (!platform || !handle) {
      return jsonResponse(400, { error: "INVALID_REQUEST" });
    }
    const { data, error } = await supabase.rpc("manage_social_link", {
      p_user_id: claims.sub,
      p_action: "add",
      p_platform: platform,
      p_handle: handle,
      p_social_link_id: null,
    });
    if (error) {
      console.error("manage_social_link add rpc error", error);
      return jsonResponse(500, { error: "DB_ERROR" });
    }
    const result = data as
      | { social_link_id?: string; error?: string }
      | null;
    if (result?.error === "ALREADY_LINKED") {
      return jsonResponse(409, { error: "ALREADY_LINKED" });
    }
    if (result?.error === "HANDLE_TAKEN") {
      return jsonResponse(409, { error: "HANDLE_TAKEN" });
    }
    if (result?.error === "INVALID_REQUEST") {
      return jsonResponse(400, { error: "INVALID_REQUEST" });
    }
    if (!result?.social_link_id) {
      console.error("manage_social_link add returned unexpected shape", result);
      return jsonResponse(500, { error: "DB_ERROR" });
    }
    return jsonResponse(200, { social_link_id: result.social_link_id });
  }

  if (body.action === "unlink") {
    const socialLinkId =
      typeof (body as UnlinkRequest).social_link_id === "string" &&
        UUID_RE.test((body as UnlinkRequest).social_link_id as string)
        ? ((body as UnlinkRequest).social_link_id as string)
        : null;
    if (!socialLinkId) {
      return jsonResponse(400, { error: "INVALID_REQUEST" });
    }
    const { data, error } = await supabase.rpc("manage_social_link", {
      p_user_id: claims.sub,
      p_action: "unlink",
      p_platform: null,
      p_handle: null,
      p_social_link_id: socialLinkId,
    });
    if (error) {
      console.error("manage_social_link unlink rpc error", error);
      return jsonResponse(500, { error: "DB_ERROR" });
    }
    const result = data as { ok?: boolean; error?: string } | null;
    if (result?.error === "LINK_NOT_FOUND") {
      return jsonResponse(404, { error: "LINK_NOT_FOUND" });
    }
    if (result?.error === "INVALID_REQUEST") {
      return jsonResponse(400, { error: "INVALID_REQUEST" });
    }
    if (!result?.ok) {
      console.error(
        "manage_social_link unlink returned unexpected shape",
        result,
      );
      return jsonResponse(500, { error: "DB_ERROR" });
    }
    return jsonResponse(200, { ok: true });
  }

  return jsonResponse(400, { error: "INVALID_REQUEST" });
});

-- US-035 — RPC backing the manage-social-link edge function.
--
-- Contract: public.manage_social_link(p_user_id, p_action, p_platform,
--   p_handle, p_social_link_id) returns jsonb.
--   On 'add' success:    {"social_link_id": "<uuid>"}.
--   On 'unlink' success: {"ok": true}.
--   On conflict:         {"error": "ALREADY_LINKED" | "HANDLE_TAKEN"
--                                | "LINK_NOT_FOUND" | "INVALID_REQUEST"}.
--
-- Atomicity: a single INSERT (add) or a single UPDATE (unlink) run inside
-- the function's implicit transaction. An add that would violate either
-- partial unique index (user_platform_uniq / platform_handle_uniq) is
-- caught and mapped; anything else is re-raised as 500 for the edge
-- function to log.
--
-- Handle normalization: the edge function is responsible for trimming +
-- stripping the leading '@'. The RPC accepts citext and trusts the caller.
--
-- Auth: revoked from anon/authenticated/public. Only service_role (used
-- by the edge function) may execute.

create or replace function public.manage_social_link(
  p_user_id uuid,
  p_action text,
  p_platform public.platform default null,
  p_handle extensions.citext default null,
  p_social_link_id uuid default null
) returns jsonb
language plpgsql
set search_path = ''
as $$
declare
  v_new_id uuid;
  v_updated_id uuid;
  v_constraint text;
begin
  if p_action = 'add' then
    if p_platform is null or p_handle is null or length(trim(p_handle::text)) = 0 then
      return jsonb_build_object('error', 'INVALID_REQUEST');
    end if;

    insert into public.social_links (user_id, platform, handle)
    values (p_user_id, p_platform, p_handle)
    returning id into v_new_id;
    return jsonb_build_object('social_link_id', v_new_id);

  elsif p_action = 'unlink' then
    if p_social_link_id is null then
      return jsonb_build_object('error', 'INVALID_REQUEST');
    end if;

    update public.social_links
       set status = 'unlinked'::public.social_link_status,
           updated_at = pg_catalog.now()
     where id = p_social_link_id
       and user_id = p_user_id
       and status <> 'unlinked'::public.social_link_status
     returning id into v_updated_id;

    if v_updated_id is null then
      return jsonb_build_object('error', 'LINK_NOT_FOUND');
    end if;
    return jsonb_build_object('ok', true);

  else
    return jsonb_build_object('error', 'INVALID_REQUEST');
  end if;

exception
  when unique_violation then
    -- Partial unique indexes scoped to `status <> 'unlinked'` (us_004).
    -- Update this branch if us_004 ever renames the indexes.
    get stacked diagnostics v_constraint = constraint_name;
    if v_constraint = 'social_links_user_platform_uniq' then
      return jsonb_build_object('error', 'ALREADY_LINKED');
    elsif v_constraint = 'social_links_platform_handle_uniq' then
      return jsonb_build_object('error', 'HANDLE_TAKEN');
    else
      raise;
    end if;
end;
$$;

revoke all on function public.manage_social_link(
  uuid, text, public.platform, extensions.citext, uuid
) from public;
revoke all on function public.manage_social_link(
  uuid, text, public.platform, extensions.citext, uuid
) from anon, authenticated;
grant execute on function public.manage_social_link(
  uuid, text, public.platform, extensions.citext, uuid
) to service_role;

comment on function public.manage_social_link(
  uuid, text, public.platform, extensions.citext, uuid
) is 'US-035 manage-social-link RPC. Called only by the manage-social-link edge function via service_role. Add inserts a new social_links row; unlink sets status=unlinked (partial unique index releases).';

